-- DCR report Of Last Three Month --->Local

select BranchID,     BranchName,   OpeningBankBalance,  OpeningCashBalance,  TotalDisbursement,       TotalCollection,     InsuranceCollection, WithdrawlFromBank,   WithdrawlFromDO,       PassbookIncome,      OtherIncome,  WriteOffCollection,  DepositAtBank,       TransferToDO,       AdministrationExpenses,    PersonalExpenses,    ClosingBankBalance,  ClosingCashBalance,       DateStamp,    Sundry,       DeathClaim,   DailyProcess, MeetingDate,  ProcessingFees,       FundRecHO,    FundRecOther, FundRecDO,    CashRecOthBranch,    SurplusCash,  Administrative,       SavingAmtColl,       Fund_TT_DO,   Fund_TT_HO,   Fund_TT_OtherBank,   Cash_TT_OtherBranch, WUP,       SavingWithdrawal,    PersonalAdvAgnstSalary,    OfficeRent,   DailyWages,   BankCharges,       SavingAmtCollOther,  SavingWithdrawalOther,     MicroATMCollection,  MicroATMWithdrawl,       TotalDisbursementBank,     TotalDisbursementHO, CECFeesCollection,   MHCFeesCollection,       FundPullOutToHO,     TotalCollectionHO,   KaleidofinColl,      RebatePaymentInttColl,       RebatePaymentPF,     StampPeperColl,      CashDipositInHO,     CashDipositCharge,       NoOfPatients, DigiCollFingPay,     AccidentalInsurance, ClothDistributionCollection,       MInsuranceCollection,      HealthInsurance,     UPI_Collection,       MInsuranceCollectionByCashpor,    MInsWavedOff, AdvanceUPI_Collection,       AdjustmentUPI_Collection,count(*)
from rptdailyclosingdtl where meetingdate between'2022-01-01' and '2022-03-31'
group by BranchID,   BranchName,   OpeningBankBalance,  OpeningCashBalance,  TotalDisbursement,       TotalCollection,     InsuranceCollection, WithdrawlFromBank,   WithdrawlFromDO,       PassbookIncome,      OtherIncome,  WriteOffCollection,  DepositAtBank,       TransferToDO,       AdministrationExpenses,    PersonalExpenses,    ClosingBankBalance,  ClosingCashBalance,       DateStamp,    Sundry,       DeathClaim,   DailyProcess, MeetingDate,  ProcessingFees,       FundRecHO,    FundRecOther, FundRecDO,    CashRecOthBranch,    SurplusCash,  Administrative,       SavingAmtColl,       Fund_TT_DO,   Fund_TT_HO,   Fund_TT_OtherBank,   Cash_TT_OtherBranch, WUP,       SavingWithdrawal,    PersonalAdvAgnstSalary,    OfficeRent,   DailyWages,   BankCharges,       SavingAmtCollOther,  SavingWithdrawalOther,     MicroATMCollection,  MicroATMWithdrawl,       TotalDisbursementBank,     TotalDisbursementHO, CECFeesCollection,   MHCFeesCollection,       FundPullOutToHO,     TotalCollectionHO,   KaleidofinColl,      RebatePaymentInttColl,       RebatePaymentPF,     StampPeperColl,      CashDipositInHO,     CashDipositCharge,       NoOfPatients, DigiCollFingPay,     AccidentalInsurance, ClothDistributionCollection,       MInsuranceCollection,      HealthInsurance,     UPI_Collection,       MInsuranceCollectionByCashpor,    MInsWavedOff, AdvanceUPI_Collection,       AdjustmentUPI_Collection
order by meetingdate,branchid
